 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { VirtualMachineModelGroupVersionKind } from '@kubevirt-utils/models';
 7	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 8	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Radio, Stack, StackItem, Text, TextVariants, Title } from '@patternfly/react-core';
10	
11	import { entireVMSelected } from '../utils';
12	
13	import SelectMigrationDisksTable from './components/SelectMigrationDisksTable';
14	
15	type VirtualMachineMigrationDetailsProps = {
16	  pvcs: IoK8sApiCoreV1PersistentVolumeClaim[];
17	  selectedPVCs: IoK8sApiCoreV1PersistentVolumeClaim[];
18	  setSelectedPVCs: Dispatch<SetStateAction<IoK8sApiCoreV1PersistentVolumeClaim[]>>;
19	  vm: V1VirtualMachine;
20	};
21	
22	const VirtualMachineMigrationDetails: FC<VirtualMachineMigrationDetailsProps> = ({
23	  pvcs,
24	  selectedPVCs,
25	  setSelectedPVCs,
26	  vm,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	
30	  const allVolumes = entireVMSelected(selectedPVCs);
31	
32	  return (
33	    <Stack hasGutter>
34	      <StackItem>
35	        <Title headingLevel="h2">{t('Migration details')}</Title>
36	        <Text component={TextVariants.p}>
37	          {t('Select the storage to migrate for')}
38	          <ResourceLink
39	            groupVersionKind={VirtualMachineModelGroupVersionKind}
40	            inline
41	            name={getName(vm)}
42	            namespace={getNamespace(vm)}
43	          />
44	        </Text>
45	      </StackItem>
46	      <StackItem>
47	        <Radio
48	          id="all-volumes"
49	          isChecked={allVolumes}
50	          label={t('The entire VirtualMachine')}
51	          name="volumes"
52	          onChange={() => setSelectedPVCs(null)}
53	        />
54	        <Radio
55	          id="selected-volumes"
56	          isChecked={!allVolumes}
57	          label={t('Selected volumes')}
58	          name="volumes"
59	          onChange={() => setSelectedPVCs([])}
60	        />
61	      </StackItem>
62	      {!allVolumes && (
63	        <StackItem>
64	          <SelectMigrationDisksTable
65	            pvcs={pvcs}
66	            selectedPVCs={selectedPVCs}
67	            setSelectedPVCs={setSelectedPVCs}
68	            vm={vm}
69	          />
70	        </StackItem>
71	      )}
72	    </Stack>
73	  );
74	};
75	
76	export default VirtualMachineMigrationDetails;

